use std::sync::{Arc, Mutex};
use std::thread;

fn main() {
    let counter = Arc::new(Mutex::new(0));
    let counter1_clone = Arc::clone(&counter);
    let counter2_clone = Arc::clone(&counter);

    let handle1 = thread::spawn(move || {
        println!("Thread 1: Attempting to lock...");
        let mut num = counter1_clone.lock().unwrap();
        *num += 5;
        println!("Thread 1: Value updated.");
    });

    let handle2 = thread::spawn(move || {
        thread::sleep(std::time::Duration::from_millis(50));
        println!("Thread 2: Attempting to lock...");
        let mut num = counter2_clone.lock().unwrap();
        *num += 1;
        println!("Thread 2: Value updated.");
    });

    handle1.join().unwrap();
    handle2.join().unwrap();

    let final_value = counter.lock().unwrap();
    println!("nFinal shared count: {}", *final_value);
}

use std::sync::{Arc, Mutex};
use std::thread;

fn main() {
    let counter = Arc::new(Mutex::new(0));
    let mut handles = vec![];
    const NUM_THREADS: usize = 10;

    for _ in 0..NUM_THREADS {
        let counter_clone = Arc::clone(&counter);
        let handle = thread::spawn(move || {
            let mut num = counter_clone.lock().unwrap();
            *num += 1;
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }

    println!("Final count: {}", *counter.lock().unwrap());
}
